883	// ErrClosureGateRejected indicates a close was refused because the bead does
884	// not carry the evidence required for an automated closure: a terminal
885	// verdict event (review APPROVE with non-empty rationale, or an explicit
886	// review-skipped / manual-close marker) AND an execution-evidence marker
887	// (closing_commit_sha, session_id, or an execute-bead success event in the
888	// events history).
889	//
890	// Automated execute-loop paths (execute-bead + reviewer) always go through
891	// CloseWithEvidence. The plain Store.Close remains as the manual
892	// administration escape hatch — it bypasses the gate by design (ddx-e30e60a9
893	// acceptance §1).
894	var ErrClosureGateRejected = fmt.Errorf("closure gate: insufficient evidence")
895	
896	// ClosureGate inspects a bead and returns nil iff the close is safe. It
897	// rejects only the specific shapes that caused the 2026-04-18/20
898	// review-malfunction incidents:
899	//
900	//  1. axon-c5cc071a (silent false-closure): closed with no events AND no
901	//     closing_commit_sha. Rejected by the execution-evidence check —
902	//     closing_commit_sha must be non-empty OR at least one event must exist.
903	//  2. f7ae036f (broken APPROVE): a review event with summary=APPROVE whose
904	//     body is empty. Rejected — APPROVE with no rationale is exactly the
905	//     parse-mis-extract shape the reviewer bug produced.
906	//
907	// Beads without a review step (--no-review, no Reviewer configured, already-
908	// satisfied paths) pass the gate as long as they carry execution evidence.
909	// This keeps the surface small: the gate catches known-bad shapes, not every
910	// conceivable edge case. Additional invariants belong in future dedicated
911	// beads so the rejection reason stays auditable.
912	func ClosureGate(b *Bead) error {
913		if b == nil {
914			return fmt.Errorf("%w: nil bead", ErrClosureGateRejected)
915		}
916		hasClosingCommit := false
917		if sha, ok := b.Extra["closing_commit_sha"].(string); ok && strings.TrimSpace(sha) != "" {
918			hasClosingCommit = true
919		}
920		events := decodeBeadEvents(b.Extra["events"])
921		// Reject the axon-c5cc071a shape: no events AND no closing commit.
922		if len(events) == 0 && !hasClosingCommit {
923			return fmt.Errorf("%w: no execution evidence (empty events and no closing_commit_sha)", ErrClosureGateRejected)
924		}
925		// Reject the f7ae036f shape: an APPROVE verdict with empty rationale.
926		for _, e := range events {
927			if e.Kind == "review" && strings.EqualFold(strings.TrimSpace(e.Summary), "APPROVE") {
928				if strings.TrimSpace(e.Body) == "" {
929					return fmt.Errorf("%w: review APPROVE with empty rationale (malformed reviewer verdict)", ErrClosureGateRejected)
930				}
931			}
932		}
933		return nil
934	}
935	
936	// CloseWithEvidence sets a bead's status to closed and records agent session evidence.
937	// sessionID is the agent session that completed the work.
938	// commitSHA is the exact closing commit SHA when it is known.
939	//
940	// Enforces ClosureGate (ddx-e30e60a9): a bead cannot transition to closed
941	// via this path without a terminal verdict event plus execution evidence.
942	// Store.Close is the manual-administration escape hatch when the gate is
943	// inappropriate.
944	func (s *Store) CloseWithEvidence(id string, sessionID string, commitSHA string) error {
945		return s.Update(id, func(b *Bead) {
946			if b.Extra == nil {
947				b.Extra = make(map[string]any)
948			}
949			if sessionID != "" {
950				b.Extra["session_id"] = sessionID
951			}
952			if commitSHA != "" {
953				b.Extra["closing_commit_sha"] = commitSHA
954			}
955			if err := ClosureGate(b); err != nil {
956				// Surface via bead notes so a later operator audit can see why the
957				// close was refused; a single error path would be dropped by the
958				// Update callback signature (no error return).
959				appendClosureRejectNote(b, err)
960				return
961			}
962			b.Status = StatusClosed
963		})
964	}
965	
966	func appendClosureRejectNote(b *Bead, err error) {
967		stamp := time.Now().UTC().Format(time.RFC3339)
968		note := fmt.Sprintf("[%s] closure rejected: %v", stamp, err)
969		if b.Notes == "" {
970			b.Notes = note
971			return
972		}
973		b.Notes = b.Notes + "\n" + note
974	}
