1417	// DepAdd adds a dependency: id depends on depID.
1418	func (s *Store) DepAdd(id, depID string) error {
1419		return s.WithLock(func() error {
1420			beads, _, err := s.readAllLatestRaw()
1421			if err != nil {
1422				return err
1423			}
1424			var target *Bead
1425			depExists := false
1426			for i := range beads {
1427				if beads[i].ID == id {
1428					target = &beads[i]
1429				}
1430				if beads[i].ID == depID {
1431					depExists = true
1432				}
1433			}
1434			if target == nil {
1435				return fmt.Errorf("bead: not found: %s", id)
1436			}
1437			if !depExists {
1438				return fmt.Errorf("bead: dependency not found: %s", depID)
1439			}
1440			if id == depID {
1441				return fmt.Errorf("bead: cannot depend on self")
1442			}
1443			if target.HasDep(depID) {
1444				return nil // already exists
1445			}
1446	
1447			// Check for circular dependency
1448			depMap := make(map[string][]string)
1449			for _, b := range beads {
1450				depMap[b.ID] = b.DepIDs()
1451			}
1452			depMap[id] = append(append([]string{}, target.DepIDs()...), depID)
1453			if hasCycle(depMap, id) {
1454				return fmt.Errorf("bead: circular dependency: %s -> %s", id, depID)
1455			}
1456	
1457			target.AddDep(depID, "blocks")
1458			target.UpdatedAt = time.Now().UTC()
1459			return s.WriteAll(beads)
1460		})
1461	}
