1621	func parseDurationOr(envKey string, fallback time.Duration) time.Duration {
1622		v := os.Getenv(envKey)
1623		if v == "" {
1624			return fallback
1625		}
1626		// Try as seconds (plain number)
1627		if secs, err := strconv.ParseFloat(v, 64); err == nil {
1628			return time.Duration(secs * float64(time.Second))
1629		}
1630		// Try as Go duration
1631		if d, err := time.ParseDuration(v); err == nil {
1632			return d
1633		}
1634		return fallback
1635	}
